// Command prose preserved from the pre-Kong Cobra surface.
package cmd

type commandHelp struct {
	Short, Long, Example string
	Flags                map[string]string
}

var commandHelpCatalog = map[string]commandHelp{
	"distill:":                   {Short: "Document chunking and token counting CLI", Long: "distill is a command-line tool for splitting documents into chunks,\ncounting tokens, and distilling documents for LLM processing. Model evaluation\nand benchmarking live in the companion distill-eval binary.\n\nSubcommands:\n  count    Count tokens, characters, and lines\n  chunk    Split documents into chunks using various strategies\n  digest   Distill a document into a fact-preserving rewrite\n             digest score   Deterministic review of a digest draft (no LLM)"},
	"eval:":                      {Short: "Evaluation and model-benchmark companion for distill", Long: "distill-eval is distill's evaluation and model-benchmark companion.\n\nIt groups the heavier, model-driven workflows that are separate from the core\ndocument pipeline (count/chunk/digest, in the distill binary):\n\n  eval    score extractions against a reference — judge (LLM precision/recall/F1),\n          facts (deterministic golden-fact scoring), or structured JSON\n  grade   grade digests on merit via the pairwise judge (calibrate/tournament/\n          recognize/panel)\n  models  rank models on a task — rankings (public leaderboards), comedy, label,\n          code, trace-go\n\nAll commands read the same ~/.config/distill/config.yaml as distill (models,\nbase URL, per-role picks).", Example: "  # Judge a candidate extraction against a reference (source chunks = ground truth)\n  distill-eval eval judge --chunks chunks/ --reference ref/responses --candidates cand/responses\n\n  # Deterministic golden-fact precision/recall (no LLM, no network)\n  distill-eval eval facts --help\n\n  # Deterministic schema-backed JSON extraction scoring\n  distill-eval eval structured --help\n\n  # Grade digests on merit via the pairwise judge\n  distill-eval grade --help\n\n  # Show per-role model picks derived from public leaderboards\n  distill-eval models rankings show"},
	"eval:eval":                  {Short: "Score extractions against a reference"},
	"eval:models":                {Short: "Rank models on a task"},
	"distill:chunk":              {Short: "Split a document into chunks", Long: "Split a document into chunks using various strategies.\n\nModes:\n  headings   Split at markdown headings (default)\n  semantic   Split by embedding similarity (requires a provider API key)\n  cramit     Dense sentence packing\n\nUse - to read the document from stdin.", Example: "", Flags: map[string]string{"clean": "Force transcript cleaning even when format detection is unsure", "coherence-window": "Semantic mode: two-sided coherence window for break validation (0 = engine default)", "embedding-model": "Embedding model name for semantic mode (e.g. text-embedding-3-small). Falls back to $DISTILL_EMBEDDING_MODEL when unset.", "format": "Output format for manifest", "local": "Use the local embedding profile (local_embedding_model/local_embedding_endpoint) instead of the remote OpenRouter default.", "max-chunk-chars": "Semantic mode: split chunk groups larger than this many chars (0 = engine default)", "max-tokens": "Target max tokens per chunk", "min-chunk-chars": "Semantic mode: merge chunk groups smaller than this many chars (0 = engine default)", "mode": "Chunking mode: headings, semantic, cramit", "no-clean": "Do not auto-clean detected transcript (VTT/SRT) input", "out-dir": "Output directory (default: temp dir)", "overlap": "Tokens of overlap between chunks", "provider": "Embedding provider for semantic mode (openrouter, openai, gemini)", "smoothing-window": "Semantic mode: moving-average window over similarity scores (0 = engine default)", "threshold": "Similarity threshold for semantic mode"}},
	"distill:count":              {Short: "Count tokens, characters, and lines", Long: "Count estimated tokens, characters, and lines in a file or stdin.", Example: "", Flags: map[string]string{"format": "Output format: json or plain"}},
	"distill:digest":             {Short: "Distill a document into a fact-preserving rewrite", Long: "Distill a long document into a cohesive rewrite without any single model\ncall holding the whole source: chunk the document, extract atomic facts from\neach chunk, compile them, then rewrite the compiled facts in a target style.\n\nPathspecs may be files, directories, or globs. Multiple matched files are\ncombined into one source with file-boundary headings. Use - to read stdin.\n\nRequires a text model (--model / $DISTILL_MODEL) that resolves to a built-in\nWormhole provider, plus the matching provider API key. --base-url is local-only.", Example: "", Flags: map[string]string{"appendix": "Append the verbatim extracted facts as a lossless appendix (recovers tables/ranked lists the prose stage samples away)", "artifacts": "Artifacts directory (default: temp dir)", "base-url": "Local OpenAI-compatible base URL. Remote custom API endpoints are disabled; use built-in Wormhole providers.", "cascade": "Run one extra extraction pass for fresh chunks whose source-specific capture is below the configured threshold", "cascade-threshold": "Source-specific capture ratio below which --cascade fires (0 uses config cascade_min_capture; 0 after config disables)", "check-precision": "Judge final article sentences against extracted facts and write responses/precision.json", "chunk-size": "Character budget per chunk (min 1000)", "cite": "Generate with temporary [F#] fact citations, verify coverage, then strip markers from the final article", "clean": "Force transcript cleaning even when format detection is unsure", "concurrency": "Max parallel chunk extractions (default from config, else 4)", "context": "Free-text guidance to steer the rewrite's emphasis/framing (injected into outline/section/edit prompts, never extraction)", "context-file": "Read steering context from a file (mutually exclusive with --context)", "deepseek": "Use the direct DeepSeek profile (deepseek_model/deepseek_base_url) with $DEEPSEEK_API_KEY.", "doc-context": "Generate a compact document-context header for research prompts (opt-in; extraction remains chunk-grounded)", "dry-run": "Plan chunks, role models, endpoints, and artifact paths without making provider calls", "facts": "Path for the compiled facts checkpoint (default: <artifacts>/facts.compiled.md)", "fuse": "Run the fuse stage that merges per-chunk notes before writing (off by default; can time out on large inputs)", "local": "Use the local model profile (local_model/local_base_url) instead of the remote OpenRouter default. The local endpoint gets $DISTILL_LOCAL_API_KEY (never $OPENAI_API_KEY).", "max-calls": "Abort before provider calls if the planned paid-call count exceeds this ceiling (0 disables)", "max-sections": "max outline sections in cluster-outline mode (0 = uncapped; unset = config digest.max_sections)", "max-tokens": "cl100k_base preflight budget per chunk (remote profile only; 0 disables)", "max-words": "Fail if the final article has more than this many words (0 disables)", "merge-facts": "Cluster and merge near-duplicate extracted facts before outlining", "merge-threshold": "Cosine similarity threshold for --merge-facts clustering (0 uses config merge_facts_threshold)", "min-cited": "Fail if cited fact coverage is below this ratio (0 disables; use with --cite)", "min-coverage": "Fail (non-zero exit) if the fraction of extracted specifics surviving in the article is below this ratio (0 disables)", "min-precision": "Fail if sentence support precision is below this ratio (implies --check-precision)", "min-words": "Fail if the final article has fewer than this many words (0 disables)", "model": "Text model for extraction and rewrite. Falls back to $DISTILL_MODEL.", "no-cache": "Skip digest caches: neither read nor store output articles or research responses", "no-clean": "Do not auto-clean detected transcript (VTT/SRT) input", "no-edit": "Skip the editor stage that polishes the writer draft", "out": "Output path for the rewrite (default: <source>.distilled.md)", "outline-from-clusters": "Use merged fact clusters to synthesize the outline (requires --merge-facts)", "repair": "After writing, run one targeted reinsert pass for extracted specifics that did not survive into the article (best-of by coverage; never lowers it)", "research-cache": "Reuse per-chunk research responses across runs (disabled by --no-cache)", "resume": "Reuse complete artifacts from a previous run in --artifacts to avoid repeated paid calls (use --resume=false to force regeneration)", "retries": "Per-call retry attempts for outline/section/edit on transient errors (default from config, else 3)", "reuse-facts": "Reuse an existing compiled-facts checkpoint (skip extraction)", "style": "Target style for the rewrite (default from config)", "target-facts": "Keep the most representative N extracted facts before writing (0 disables)", "timeout": "Per-LLM-call timeout in seconds (default from config, else 300)"}},
	"distill:digest-score":       {Short: "Deterministically review digest.md drafts: fact recall, tension preservation, hygiene (no LLM)", Long: "", Example: "", Flags: map[string]string{"checks": "Doc-specific tension/hygiene checks JSON", "copy-penalty": "Composite score = recall - copyPenalty*overlap (higher punishes copiers harder)", "digests": "Directory whose */digest.md files are reviewed", "expected": "Directory of chunk-*.json golden-fact fixtures", "out": "Write a self-contained HTML report to this path", "source": "Source document, for the verbatim-overlap (copying) signal"}},
	"eval:eval facts":            {Short: "Score per-chunk extractions against golden-fact fixtures (deterministic, no LLM)", Long: "", Example: "", Flags: map[string]string{"candidates": "Comma-separated per-chunk responses directories to score [required]", "expected": "Directory of chunk-*.json golden-fact fixtures", "out": "Output directory for INDEX.md and <name>.summary.md (default: stdout only)"}},
	"eval:eval judge":            {Short: "Score candidate extractions against a reference with an LLM judge", Long: "Judge one or more candidate extraction sets against a reference, chunk by\nchunk, using the source chunks as ground truth. Produces per-candidate\njudgments.jsonl + summary.md and a ranked INDEX.md (precision/recall/F1).\n\nInputs are the artifact directories produced by distill digest runs:\n  --chunks      the source chunks dir (chunk-NNN.md)\n  --reference   a trusted extraction's responses dir\n  --candidates  comma-separated candidate response dirs to score\n\nThe judge is the built-in OpenAI-compatible client by default; pass --judge-cmd\nto judge with an external CLI instead (e.g. --judge-cmd \"codex exec -\").", Example: "", Flags: map[string]string{"base-url": "Local OpenAI-compatible base URL; remote custom endpoints are disabled", "candidates": "Comma-separated candidate response directories [required]", "chunks": "Source chunks directory (chunk-NNN.md) [required]", "deepseek": "Use the direct DeepSeek profile with $DEEPSEEK_API_KEY.", "judge-cmd": "External judge command run with the prompt on stdin (e.g. \"codex exec -\"). Overrides --judge-model/--base-url.", "judge-model": "Judge model for the built-in endpoint (falls back to $DISTILL_MODEL or config)", "judge-timeout": "Per-judge-call timeout in seconds for --judge-cmd (0 = no timeout)", "local": "Use the local model profile instead of the remote OpenRouter default.", "out": "Output directory for evaluations (default: temp dir)", "reference": "Reference extraction responses directory [required]"}},
	"eval:eval optimize":         {Short: "Optimize the digest research prompt against golden extraction fixtures", Long: "", Example: "", Flags: map[string]string{"budget-calls": "Maximum model calls across mutation and evaluation (0 disables)", "chunks": "Directory of chunk-*.md source chunks", "concurrency": "Maximum parallel candidate extraction calls", "expected": "Directory of chunk-*.json golden-fact fixtures", "holdout": "Optional holdout expected-dir scored but not used for acceptance", "iterations": "Mutation iterations to attempt", "model": "Extractor model override", "mutator-model": "Mutator model override (default: --model/config model)", "out": "Output directory for score-log.jsonl, candidates, and best-prompt.md", "seed": "Seed prompt path (default: configured research prompt)"}},
	"eval:eval structured":       {Short: "Score JSON extractions against a schema-backed gold file (deterministic, no LLM)", Long: "Score one or more JSON extraction candidates against a JSON Schema and gold\nJSON file. This is deterministic and uses the schema as the evaluation contract:\ninvalid JSON, type mismatches, missing required fields, and disallowed extra\nfields fail structural compliance.", Example: "", Flags: map[string]string{"candidates": "Comma-separated candidate JSON files to score [required]", "gold": "Gold JSON file [required]", "out": "Output directory for INDEX.md, summaries, and JSON reports (default: stdout only)", "schema": "JSON Schema file with optional evaluation_config fields [required]"}},
	"eval:grade":                 {Short: "Grade digests on merit as a read (currently: calibrate the pairwise judge)", Long: "", Example: "", Flags: map[string]string{}},
	"eval:grade calibrate":       {Short: "Test whether the pairwise merit judge discriminates or just guesses", Long: "Pit each digest against deterministic degradations of itself (shuffle,\ntruncate, cliche, listify) in BOTH slot orders. Because the intact digest is the\nknown-correct answer, the judge's swap-robust accuracy and position-bias rate\nreveal whether it actually reads merit or is guessing — before any paid\ntournament is run.", Example: "", Flags: map[string]string{"base-url": "Local OpenAI-compatible base URL; remote custom endpoints are disabled", "deepseek": "Use the direct DeepSeek profile with $DEEPSEEK_API_KEY.", "digests": "Directory whose */digest.md files are calibrated against", "include-source": "Also pit each digest against the raw source brief", "judge-model": "Judge model (falls back to $DISTILL_MODEL or config)", "limit": "Calibrate on the first N digests (alphabetical); 0 = all", "local": "Use the local model profile instead of the remote OpenRouter default.", "models": "Comma-separated digest dir names to calibrate (overrides --limit)", "source": "Source document (for fidelity grounding + the vs-source pair)"}},
	"eval:grade panel":           {Short: "de-biased leave-one-out panel tournament (no model judges its own digest)", Long: "", Example: "", Flags: map[string]string{"all": "Rank the WHOLE field, skipping the candidate gate (expensive)", "audit": "Number of random triples to audit for transitivity (cycle rate)", "base-url": "Local OpenAI-compatible base URL; remote custom endpoints are disabled", "checks": "Doc-specific checks + gate thresholds JSON", "criterion": "Judge criterion: merit | comedy | publish", "deepseek": "Use the direct DeepSeek profile with $DEEPSEEK_API_KEY.", "digests": "Directory whose */digest.md files are ranked", "dry-run": "Print the gated candidates + estimated judge-call count and exit (no judging, no spend)", "expected": "Golden-fact fixtures dir (for the candidate gate)", "judges": "comma-separated judge MODEL IDS", "local": "Use the local model profile instead of the remote OpenRouter default.", "models": "Explicit comma-separated digest dir names IN SEED ORDER (bypasses the gate)", "out": "Write a self-contained HTML report to this path", "seed": "Random seed", "source": "Source document (for fidelity grounding + overlap)", "top": "With --models/--all: cap to first N; default gate selects candidates automatically"}},
	"eval:grade recognize":       {Short: "self-recognition probe: can each judge spot its own digest?", Long: "", Example: "", Flags: map[string]string{"base-url": "Local OpenAI-compatible base URL; remote custom endpoints are disabled", "deepseek": "Use the direct DeepSeek profile with $DEEPSEEK_API_KEY.", "digests": "source dir of <model>/digest.md", "dry-run": "Print estimated judge-call count and exit (no judging, no spend)", "judges": "comma-separated judge MODEL IDS", "out": "optional HTML report path", "seed": "Random seed", "set-size": "Number of anonymized digests shown per trial", "trials": "Number of recognition trials per judge"}},
	"eval:grade tournament":      {Short: "Rank digests by merit via an order-swapped pairwise judge (merge sort + cycle audit)", Long: "Rank digests on merit as a read using the calibrated pairwise judge. Each\nmatchup is judged in BOTH slot orders (a decisive win must survive the swap;\ndisagreement is an uncertain tie). Uses ~N*log N comparisons via merge sort,\nseeded by the deterministic composite order for stable tie-breaks, then audits\nrandom triples for transitivity. Reports the ranking plus flip/cycle/grounded\ntrust stats. Run 'calibrate' first to confirm the judge is sound.", Example: "", Flags: map[string]string{"all": "Rank the WHOLE field, skipping the candidate gate (expensive)", "audit": "Number of random triples to audit for transitivity (cycle rate)", "base-url": "Local OpenAI-compatible base URL; remote custom endpoints are disabled", "checks": "Doc-specific checks + gate thresholds JSON", "deepseek": "Use the direct DeepSeek profile with $DEEPSEEK_API_KEY.", "digests": "Directory whose */digest.md files are ranked", "dry-run": "Print the gated candidates + estimated judge-call count and exit (no judging, no spend)", "expected": "Golden-fact fixtures dir (for the candidate gate)", "judge-model": "Judge model (falls back to $DISTILL_MODEL or config)", "local": "Use the local model profile instead of the remote OpenRouter default.", "models": "Explicit comma-separated digest dir names IN SEED ORDER (bypasses the gate)", "out": "Write a self-contained HTML report to this path", "source": "Source document (for fidelity grounding + overlap)", "top": "With --models/--all: cap to first N; default gate selects candidates automatically"}},
	"eval:models code":           {Short: "Rank models by unit-test pass-rate on coding problems (compiles + runs model code)", Long: "Each model in the roster writes Go solutions to a fixture of coding problems;\neach solution is statically scanned for dangerous imports/calls, then compiled and\nunit-tested in an isolated temp dir, scored by pass-rate (no LLM judge).\n\nSAFETY: this COMPILES AND RUNS model-generated Go on your machine. The default\nrunner is temp-dir + offline (GOPROXY=off) + per-problem timeout + AST static-scan\n— defense-in-depth, NOT a sandbox. You must pass --i-understand-code-execution.", Example: "", Flags: map[string]string{"base-url": "Local OpenAI-compatible base URL; remote custom endpoints are disabled", "concurrency": "Max models evaluated concurrently", "deepseek": "Use the direct DeepSeek profile with $DEEPSEEK_API_KEY.", "i-understand-code-execution": "REQUIRED: acknowledge this compiles+runs model-generated code on your machine", "local": "Use the local model profile instead of the remote OpenRouter default.", "models": "Comma-separated model roster [required]", "out": "Write a self-contained HTML report to this path", "problems": "Coding-problems fixture ({problems})", "seed": "Random seed (advisory)", "timeout": "Per-problem timeout in seconds"}},
	"eval:models comedy":         {Short: "Rank models by how funny their short comedy bits are (de-biased leave-one-out panel)", Long: "Each model in the roster writes a short comedy bit for every topic in the\nfixture; the bits are then ranked by the SAME de-biased leave-one-out panel as\nthe digest tournament (order-swapped pairwise, merge sort, cycle audit), but with\na \"which bit is funnier\" criterion instead of faithfulness. One model failing to\ngenerate is skipped, not fatal. The subjective counterpart to the label eval.", Example: "", Flags: map[string]string{"audit": "Number of random triples to audit for transitivity (cycle rate)", "base-url": "Local OpenAI-compatible base URL; remote custom endpoints are disabled", "concurrency": "Max models generating bits concurrently", "deepseek": "Use the direct DeepSeek profile with $DEEPSEEK_API_KEY.", "judges": "comma-separated judge MODEL IDS (leave-one-out panel)", "local": "Use the local model profile instead of the remote OpenRouter default.", "models": "Comma-separated model roster that writes the bits [required]", "out": "Write a self-contained HTML report to this path", "seed": "Random seed (advisory)", "timeout": "Per-model generation timeout in seconds (0 = no timeout)", "topics": "Comedy topics fixture ({style, topics})"}},
	"eval:models label":          {Short: "Evaluate models on a single-label task (classification/sentiment) by exact gold match", Long: "Run a roster of models over a fixture of {id, text, gold_label} items,\nconstraining each model to one label from the fixture's allowed set, and score by\nnormalized exact match against the gold labels — deterministic, no LLM judge.\nProduces per-model accuracy, per-class precision/recall/F1, macro-F1, and an\nout-of-taxonomy count, ranked into a routing table (optionally as HTML via --out).", Example: "", Flags: map[string]string{"base-url": "Local OpenAI-compatible base URL; remote custom endpoints are disabled", "concurrency": "Max concurrent per-item model calls", "deepseek": "Use the direct DeepSeek profile with $DEEPSEEK_API_KEY.", "fixtures": "Label fixture JSON ({task, allowed_labels, items}) [required]", "local": "Use the local model profile instead of the remote OpenRouter default.", "models": "Comma-separated model roster to evaluate [required]", "out": "Write a self-contained HTML routing report to this path", "seed": "Seed passed through for reproducibility (advisory; SDK applies where supported)", "task": "Task: classification or sentiment [required]", "timeout": "Per-run timeout in seconds (0 = no timeout)"}},
	"eval:models rankings":       {Short: "Inspect and update remote model rankings → per-role config", Long: "Rankings come from public benchmark boards crosswalked against the cost-capped roster; show prints current picks, apply re-derives them (apply/fetch land in later phases).", Example: "", Flags: map[string]string{}},
	"eval:models rankings apply": {Short: "Re-derive per-role model picks from rankings and write them into config.yaml", Long: "", Example: "", Flags: map[string]string{"dry-run": "Show changes without writing config.yaml."}},
	"eval:models rankings fetch": {Short: "Fetch board rankings via the defuddle CLI and update rankings.yaml", Long: "Fetches each board's URL through the defuddle CLI, rendering JavaScript boards when requested, parses the leaderboard table, and writes matched roster scores into rankings.yaml; then run apply.", Example: "", Flags: map[string]string{"board": "Fetch only this board key.", "render": "Pass --render to defuddle for boards configured with render: true.", "timeout": "Per-board timeout in seconds."}},
	"eval:models rankings show":  {Short: "Print the current per-role model picks from config", Long: "", Example: "", Flags: map[string]string{"local": "Use the local model profile instead of the remote OpenRouter default."}},
	"eval:models trace-go":       {Short: "Rank models by exact stdout prediction on deterministic Go programs", Long: "Run a roster of models over trusted single-file Go programs and score the\nlast non-empty model output line against byte-exact stdout gold. The fixture\nprograms are executed locally to verify or generate gold; model output is never\nexecuted. Model calls use greedy decoding (temperature 0). Use only trusted\nfixtures. Task progress is printed as each model call completes, and HTML reports\ninclude per-task predictions/errors.", Example: "", Flags: map[string]string{"base-url": "Local OpenAI-compatible base URL; remote custom endpoints are disabled", "concurrency": "Max concurrent per-task model calls", "deepseek": "Use the direct DeepSeek profile with $DEEPSEEK_API_KEY.", "fixtures": "Trace fixture JSON ({tasks})", "local": "Use the local model profile instead of the remote OpenRouter default.", "models": "Comma-separated model roster [required]", "only": "Comma-separated task IDs to run (default: all tasks)", "out": "Write a self-contained HTML routing report to this path", "skip": "Comma-separated task IDs to skip after --only is applied", "task-timeout": "Per-task model-call timeout in seconds (0 = no timeout)", "timeout": "Per-model timeout in seconds (0 = no timeout)", "verify-timeout": "Per-fixture go-run timeout in seconds (0 = no timeout)"}},
}
